import{c as a,Q as t,j as r,m as o}from"./chunks/framework.BXc4yaFE.js";const f=JSON.parse('{"title":"Interconnects AI — 2026-05-20","description":"","frontmatter":{"title":"Interconnects AI — 2026-05-20","date":"2026-05-20T00:00:00.000Z","source":"Interconnects AI","type":"ai-news"},"headers":[],"relativePath":"research/ai-news/2026-05/2026-05-20-interconnects-ai.md","filePath":"research/ai-news/2026-05/2026-05-20-interconnects-ai.md","lastUpdated":1779894392000}'),n={name:"research/ai-news/2026-05/2026-05-20-interconnects-ai.md"};function s(i,e,h,l,c,p){return t(),r("div",null,[...e[0]||(e[0]=[o('<h1 id="🔗-interconnects-ai-—-2026-05-20" tabindex="-1">🔗 Interconnects AI — 2026-05-20 <a class="header-anchor" href="#🔗-interconnects-ai-—-2026-05-20" aria-label="Permalink to &quot;🔗 Interconnects AI — 2026-05-20&quot;">​</a></h1><blockquote><p>Nathan Lambert 的 RLHF、模型訓練深度專欄 來源：<a href="https://www.interconnects.ai/feed" target="_blank" rel="noreferrer">Interconnects AI</a></p></blockquote><hr><h2 id="latest-open-artifacts-21-open-model-bonanza-gemma-4-deepseek-v4-kimi-k2-6-mimo-2-5-glm-5-1-others-on-caisi-s" tabindex="-1"><a href="https://www.interconnects.ai/p/latest-open-artifacts-21-open-model" target="_blank" rel="noreferrer">Latest open artifacts (#21): Open model bonanza! Gemma 4, DeepSeek V4, Kimi K2.6, MiMo 2.5, GLM-5.1 &amp; others. On CAISI&#39;s…</a> <a class="header-anchor" href="#latest-open-artifacts-21-open-model-bonanza-gemma-4-deepseek-v4-kimi-k2-6-mimo-2-5-glm-5-1-others-on-caisi-s" aria-label="Permalink to &quot;[Latest open artifacts (#21): Open model bonanza! Gemma 4, DeepSeek V4, Kimi K2.6, MiMo 2.5, GLM-5.1 &amp; others. On CAISI&#39;s…](https://www.interconnects.ai/p/latest-open-artifacts-21-open-model)&quot;">​</a></h2><p><em>🔗 Interconnects AI | 2026-05-16</em></p><p>This month was packed, with all open frontier labs, including DeepSeek, releasing new models. The latter prompted an evaluation by the <a href="https://www.nist.gov/news-events/news/2026/05/caisi-evaluation-deepseek-v4-pro" target="_blank" rel="noreferrer">Center for AI Standards and Innovation (CAISI)</a>, which has evaluated open models and their risks in the past. Their result is that open models lag behind the American frontier, with the gap becoming wider over time:</p><p><a href="https://substackcdn.com/image/fetch/$s_!4DPW!,f_auto,q_auto:good,fl_progressive:steep/https%3A%2F%2Fsubstack-post-media.s3.amazonaws.com%2Fpublic%2Fimages%2F9d954e79-7538-48b7-bd3c-c6cd21421329_2800x1856.png" target="_blank" rel="noreferrer"></a></p><p>For the report, they calculate an Elo score based on <a href="https://en.wikipedia.org/wiki/Item_response_theory" target="_blank" rel="noreferrer">Item Response Theory</a>, which is commonly used to compare different models, even when they were tested on a different set of benchmarks. For V4, CAISI used nine different benchmarks:</p><p><a href="https://substackcdn.com/image/fetch/$s_!cVg4!,f_auto,q_auto:good,fl_progressive:steep/https%3A%2F%2Fsubstack-post-media.s3.amazonaws.com%2Fpublic%2Fimages%2F206a5c61-cc5b-423e-8db6-28f5f209291c_1546x1284.png" target="_blank" rel="noreferrer"></a></p><p>The huge Elo difference is explained by DeepSeek V4s bad score in CTF-Archive-Diamond (which was only run with a subset of the benchmark and extrapolated with IRT for V4), PortBench (a CAISI-private benchmark) and ARC-AGI-2 (with a different scoring method than the public leaderboards). The differences in these benchmark have a huge impact on the overall Elo, which can exacerbate the difference in capabilities.</p><p>When using <a href="https://epoch.ai/eci" target="_blank" rel="noreferrer">Epoch AI&#39;s ECI</a>, which also uses IRT over a set of different benchmarks, we see that the gap roughly stays between 3-7 months since R1:</p><p><a href="https://substackcdn.com/image/fetch/$s_!qx4F!,f_auto,q_auto:good,fl_progressive:steep/https%3A%2F%2Fsubstack-post-media.s3.amazonaws.com%2Fpublic%2Fimages%2F608dea3a-c43c-4bf0-a5c2-f5b9bb7e63d3_2400x1500.png" target="_blank" rel="noreferrer"></a>The open&lt;&gt;closed gap in ECI (from <a href="https://mcnair.center/china/" target="_blank" rel="noreferrer">https://mcnair.center/china/</a>)</p><p>However, both CAISI and ECI paint an incomplete picture, as both use standardized (and simple) setups to compare the capabilities of models. To be more concrete: Coding tasks are evaluated using access to bash and a for-loop with a fixed budget of tokens, not with a harness such as Claude Code or OpenCode, which models are trained in! These setups result in benchmarks claiming that porting applications to another language is <a href="https://programbench.com/" target="_blank" rel="noreferrer">currently not possible</a>, while <a href="https://github.com/oven-sh/bun/pull/30412" target="_blank" rel="noreferrer">Bun has been ported from Zig to Rust with 1 million LOC changes</a><a href="https://www.interconnects.ai/feed#footnote-1" target="_blank" rel="noreferrer">1</a>.</p><p>Therefore, we would argue that a frontier comparison of open and closed models would also need to elicit the capabilities of all models better, which means the usage of the preferred harnesses, as well as model-specific prompting.</p><p>This section was written primarily by Florian. An interesting dynamic within Interconnects is that Florian believes more in the proximity of open frontier models to closed alternatives in true performance. Nathan thinks the benchmarks are imperfect as well, but thinks the closed models are ahead by more. We&#39;re going to continue to unpack this in our future content.</p><p><a href="https://www.interconnects.ai/p/latest-open-artifacts-21-open-model?utm_source=substack&amp;utm_medium=email&amp;utm_content=share&amp;action=share" target="_blank" rel="noreferrer">Share</a></p><h3 id="our-picks" tabindex="-1"><strong>Our Picks</strong> <a class="header-anchor" href="#our-picks" aria-label="Permalink to &quot;**Our Picks**&quot;">​</a></h3><ul><li><strong><a href="https://huggingface.co/XiaomiMiMo/MiMo-V2.5-Pro" target="_blank" rel="noreferrer">MiMo-V2.5-Pro</a></strong> by <a href="https://huggingface.co/XiaomiMiMo" target="_blank" rel="noreferrer">XiaomiMiMo</a>: Avid Artifacts readers know that Xiaomi has been working on open models for a while; its debut was <a href="https://www.interconnects.ai/p/latest-open-artifacts-10-new-deepseek" target="_blank" rel="noreferrer">exactly one year ago</a>. The progress of its releases is remarkable, with 2.5 Pro (released under Apache 2.0) being neck and neck with other flagship models such as Kimi K2.6 and GLM-5.1 in both benchmarks and <a href="https://x.com/Designarena/status/2054776484833952000?s=20" target="_blank" rel="noreferrer">real-world usage</a>.</li></ul><p><a href="https://substackcdn.com/image/fetch/$s_!25fp!,f_auto,q_auto:good,fl_progressive:steep/https%3A%2F%2Fsubstack-post-media.s3.amazonaws.com%2Fpublic%2Fimages%2F34228788-0da1-4aea-840e-5eae68bbfa17_1200x786.jpeg" target="_blank" rel="noreferrer"></a></p><ul><li><p><strong><a href="https://huggingface.co/google/gemma-4-26B-A4B-it" target="_blank" rel="noreferrer">gemma-4-26B-A4B-it</a></strong> by <a href="https://huggingface.co/google" target="_blank" rel="noreferrer">google</a> (full Interconnects post <a href="https://www.interconnects.ai/p/gemma-4-and-what-makes-an-open-model" target="_blank" rel="noreferrer">here</a>): The long-awaited update to the Gemma series, featuring multiple sizes: <a href="https://huggingface.co/google/gemma-4-E2B-it" target="_blank" rel="noreferrer">4B</a>, <a href="https://huggingface.co/google/gemma-4-E4B-it" target="_blank" rel="noreferrer">9B</a>, and <a href="https://huggingface.co/google/gemma-4-31B-it" target="_blank" rel="noreferrer">31B</a> dense models, as well as a 26B-A4B MoE. Even more importantly, with Gemma 4, Google has decided to use Apache 2.0 as its license, which removes the uncertainty and legal challenges around interpreting custom licenses.</p></li><li><p><strong><a href="https://huggingface.co/moonshotai/Kimi-K2.6" target="_blank" rel="noreferrer">Kimi-K2.6</a></strong> by <a href="https://huggingface.co/moonshotai" target="_blank" rel="noreferrer">moonshotai</a>: An update to the Kimi series, delivering stronger performance across the board and making it one of the best open models out there yet again. They also focus on long-horizon performance, showing that open models are capable of running over hours to complete tasks or optimize performance. Given the focus of everyone to build <a href="https://github.com/karpathy/autoresearch" target="_blank" rel="noreferrer">autoresearch</a>-like systems, seeing open models catch up is important.</p></li></ul><p><a href="https://substackcdn.com/image/fetch/$s_!K_mJ!,f_auto,q_auto:good,fl_progressive:steep/https%3A%2F%2Fsubstack-post-media.s3.amazonaws.com%2Fpublic%2Fimages%2Fe08af2e3-9ce3-4ace-bec7-e8aecce5e120_10188x6520.webp" target="_blank" rel="noreferrer"></a></p><ul><li><p><strong><a href="https://huggingface.co/poolside/Laguna-XS.2" target="_blank" rel="noreferrer">Laguna-XS.2</a></strong> by <a href="https://huggingface.co/poolside" target="_blank" rel="noreferrer">poolside</a>: Poolside AI has released its first public coding-focused models, including the open-weight XS.2. Its size (33B-A3B) makes it attractive for local use, with performance on par with other models in that size range. The accompanying <a href="https://poolside.ai/blog/laguna-a-deeper-dive" target="_blank" rel="noreferrer">blog post</a> is worth a read, as is <a href="https://poolside.ai/blog/through-the-looking-glass" target="_blank" rel="noreferrer">the deep dive</a> into reward hacking during coding evaluations.</p></li><li><p><strong><a href="https://huggingface.co/deepseek-ai/DeepSeek-V4-Flash" target="_blank" rel="noreferrer">DeepSeek-V4-Flash</a></strong> by <a href="https://huggingface.co/deepseek-ai" target="_blank" rel="noreferrer">deepseek-ai</a>: DeepSeek has finally released its successor to the V3 series, which it kept updating for months. It comes in two sizes: Pro, which is a 1.6T-A49B MoE, and Flash, a 284B-13B model. Based on others&#39; experience, the latter model seems to be the real star of the show, as its performance is relatively strong, while Pro seems to underdeliver relative to its size. The <a href="https://huggingface.co/deepseek-ai/DeepSeek-V4-Pro/blob/main/DeepSeek_V4.pdf" target="_blank" rel="noreferrer">tech report</a> goes into great detail, including the architectural changes used to achieve better and cheaper long-context performance.</p></li></ul><h3 id="models" tabindex="-1"><strong>Models</strong> <a class="header-anchor" href="#models" aria-label="Permalink to &quot;**Models**&quot;">​</a></h3><h4 id="general-purpose" tabindex="-1">General Purpose <a class="header-anchor" href="#general-purpose" aria-label="Permalink to &quot;General Purpose&quot;">​</a></h4><ul><li><p><strong><a href="https://huggingface.co/Qwen/Qwen3.6-35B-A3B" target="_blank" rel="noreferrer">Qwen3.6-35B-A3B</a></strong> by <a href="https://huggingface.co/Qwen" target="_blank" rel="noreferrer">Qwen</a>: An update to the Qwen 3.5 series targeting one of the most widely used sizes.</p></li><li><p><strong><a href="https://huggingface.co/LiquidAI/LFM2.5-350M" target="_blank" rel="noreferrer">LFM2.5-350M</a></strong> by <a href="https://huggingface.co/LiquidAI" target="_blank" rel="noreferrer">LiquidAI</a>: With 28T tokens for 350M parameters, this model might be the most overtrained model out there.</p></li><li><p><strong><a href="https://huggingface.co/arcee-ai/Trinity-Large-Thinking" target="_blank" rel="noreferrer">Trinity-Large-Thinking</a></strong> by <a href="https://huggingface.co/arcee-ai" target="_blank" rel="noreferrer">arcee-ai</a>: The reasoning version of Trinity, one of the best Western open models. It has topped the OpenRouter charts for a while and can power agentic applications such as OpenClaw.</p></li><li><p><strong><a href="https://huggingface.co/zai-org/GLM-5.1" target="_blank" rel="noreferrer">GLM-5.1</a></strong> by <a href="https://huggingface.co/zai-org" target="_blank" rel="noreferrer">zai-org</a>: An update to GLM-5, improving scores across the board. The focus for this update is on long-horizon tasks.</p></li></ul><p><a href="https://www.interconnects.ai/p/latest-open-artifacts-21-open-model" target="_blank" rel="noreferrer"> Read more </a></p><hr>',27)])])}const d=a(n,[["render",s]]);export{f as __pageData,d as default};
